#!/usr/bin/env node

/**
 * Generate placeholder icons for the extension
 *
 * This script creates simple placeholder PNG icons.
 * For production, replace these with professionally designed icons.
 *
 * Usage: node scripts/generate-icons.js
 */

import { writeFileSync, mkdirSync, existsSync } from 'fs';
import { resolve, dirname } from 'path';
import { fileURLToPath } from 'url';

const __filename = fileURLToPath(import.meta.url);
const __dirname = dirname(__filename);

const PROJECT_ROOT = resolve(__dirname, '..');
const ICON_DIR = resolve(PROJECT_ROOT, 'entrypoints', 'icon');

// Icon sizes to generate
const SIZES = [16, 32, 48, 128];

/**
 * Create a simple colored square as a PNG
 * This is a minimal PNG implementation for placeholder icons
 */
function createPlaceholderPNG(size) {
  // PNG file structure
  const signature = Buffer.from([0x89, 0x50, 0x4e, 0x47, 0x0d, 0x0a, 0x1a, 0x0a]);

  // IHDR chunk
  const ihdr = createIHDRChunk(size, size);

  // IDAT chunk (image data)
  const idat = createIDATChunk(size, size);

  // IEND chunk
  const iend = createIENDChunk();

  return Buffer.concat([signature, ihdr, idat, iend]);
}

/**
 * Create IHDR chunk
 */
function createIHDRChunk(width, height) {
  const data = Buffer.alloc(13);
  data.writeUInt32BE(width, 0);
  data.writeUInt32BE(height, 4);
  data.writeUInt8(8, 8);  // bit depth
  data.writeUInt8(2, 9);  // color type (RGB)
  data.writeUInt8(0, 10); // compression method
  data.writeUInt8(0, 11); // filter method
  data.writeUInt8(0, 12); // interlace method

  return createChunk('IHDR', data);
}

/**
 * Create IDAT chunk with simple green color
 */
function createIDATChunk(width, height) {
  // Create raw image data (RGB)
  const rowSize = 1 + width * 3; // filter byte + RGB data
  const rawData = Buffer.alloc(height * rowSize);

  // Green color (#4CAF50)
  const r = 0x4C;
  const g = 0xAF;
  const b = 0x50;

  // White color for play triangle
  const wr = 0xFF;
  const wg = 0xFF;
  const wb = 0xFF;

  for (let y = 0; y < height; y++) {
    const rowOffset = y * rowSize;
    rawData[rowOffset] = 0; // No filter

    for (let x = 0; x < width; x++) {
      const pixelOffset = rowOffset + 1 + x * 3;

      // Check if pixel is inside play triangle
      const centerX = width / 2;
      const centerY = height / 2;
      const triangleSize = width * 0.4;

      // Simple play button shape (triangle pointing right)
      const tx = (x - centerX + triangleSize * 0.3) / triangleSize;
      const ty = (y - centerY) / triangleSize;

      const inTriangle = tx >= -0.5 && tx <= 0.5 && Math.abs(ty) <= (0.5 - tx);

      if (inTriangle) {
        rawData[pixelOffset] = wr;
        rawData[pixelOffset + 1] = wg;
        rawData[pixelOffset + 2] = wb;
      } else {
        rawData[pixelOffset] = r;
        rawData[pixelOffset + 1] = g;
        rawData[pixelOffset + 2] = b;
      }
    }
  }

  // Compress with zlib (deflate)
  const zlib = require('zlib');
  const compressed = zlib.deflateSync(rawData, { level: 9 });

  return createChunk('IDAT', compressed);
}

/**
 * Create IEND chunk
 */
function createIENDChunk() {
  return createChunk('IEND', Buffer.alloc(0));
}

/**
 * Create a PNG chunk with type, data, and CRC
 */
function createChunk(type, data) {
  const length = Buffer.alloc(4);
  length.writeUInt32BE(data.length, 0);

  const typeBuffer = Buffer.from(type, 'ascii');

  // Calculate CRC32 of type + data
  const crc = Buffer.alloc(4);
  const crcValue = crc32(Buffer.concat([typeBuffer, data]));
  crc.writeUInt32BE(crcValue >>> 0, 0);

  return Buffer.concat([length, typeBuffer, data, crc]);
}

/**
 * CRC32 implementation for PNG
 */
function crc32(data) {
  let crc = 0xFFFFFFFF;
  const table = getCRC32Table();

  for (let i = 0; i < data.length; i++) {
    crc = table[(crc ^ data[i]) & 0xFF] ^ (crc >>> 8);
  }

  return crc ^ 0xFFFFFFFF;
}

/**
 * Generate CRC32 lookup table
 */
function getCRC32Table() {
  const table = new Uint32Array(256);

  for (let i = 0; i < 256; i++) {
    let crc = i;
    for (let j = 0; j < 8; j++) {
      crc = crc & 1 ? 0xEDB88320 ^ (crc >>> 1) : crc >>> 1;
    }
    table[i] = crc >>> 0;
  }

  return table;
}

/**
 * Main function
 */
function main() {
  console.log('Generating placeholder icons...');

  // Ensure icon directory exists
  if (!existsSync(ICON_DIR)) {
    mkdirSync(ICON_DIR, { recursive: true });
  }

  // Generate icons for each size
