#!/usr/bin/env node

/**
 * Generate icons for the extension using sharp
 *
 * This script creates simple placeholder PNG icons with a play button design.
 * For production, replace these with professionally designed icons.
 *
 * Usage: npm run icons
 */

import sharp from 'sharp';
import { mkdirSync, existsSync } from 'fs';
import { resolve, dirname } from 'path';
import { fileURLToPath } from 'url';

const __filename = fileURLToPath(import.meta.url);
const __dirname = dirname(__filename);

const PROJECT_ROOT = resolve(__dirname, '..');
const ICON_DIR = resolve(PROJECT_ROOT, 'public', 'icon');

// Icon sizes to generate
const SIZES = [16, 32, 48, 128];

/**
 * Create an SVG icon with play button
 */
function createIconSVG(size) {
  const padding = size * 0.15;
  const center = size / 2;
  const triangleSize = size * 0.35;

  // Play triangle points (shifted slightly right for visual balance)
  const offsetX = size * 0.05;
  const x1 = center - triangleSize * 0.4 + offsetX;
  const y1 = center - triangleSize * 0.5;
  const x2 = center + triangleSize * 0.6 + offsetX;
  const y2 = center;
  const x3 = center - triangleSize * 0.4 + offsetX;
  const y3 = center + triangleSize * 0.5;

  return `
    <svg width="${size}" height="${size}" xmlns="http://www.w3.org/2000/svg">
      <defs>
        <linearGradient id="bg" x1="0%" y1="0%" x2="100%" y2="100%">
          <stop offset="0%" style="stop-color:#4CAF50;stop-opacity:1" />
          <stop offset="100%" style="stop-color:#388E3C;stop-opacity:1" />
        </linearGradient>
      </defs>
      <rect width="${size}" height="${size}" rx="${size * 0.2}" fill="url(#bg)"/>
      <polygon points="${x1},${y1} ${x2},${y2} ${x3},${y3}" fill="white"/>
    </svg>
  `;
}

/**
 * Generate icon at specified size
 */
async function generateIcon(size) {
  const svg = createIconSVG(size);
  const iconPath = resolve(ICON_DIR, `${size}.png`);

  await sharp(Buffer.from(svg))
    .png()
    .toFile(iconPath);

  console.log(`  Created: ${size}.png`);
}

/**
 * Main function
 */
async function main() {
  console.log('Generating extension icons...');
  console.log('');

  // Ensure icon directory exists
  if (!existsSync(ICON_DIR)) {
    mkdirSync(ICON_DIR, { recursive: true });
  }

  // Generate icons for each size
  for (const size of SIZES) {
    await generateIcon(size);
  }

  console.log('');
  console.log('Icons generated successfully!');
  console.log(`Location: ${ICON_DIR}`);
  console.log('');
  console.log('Note: These are placeholder icons. For production,');
  console.log('replace them with professionally designed icons.');
}

main().catch((error) => {
  console.error('Error generating icons:', error.message);
  process.exit(1);
});

