/**
 * Video detection utilities for finding video elements and sources on web pages
 * Supports detection via DOM, meta tags, network interception, and site-specific extractors
 */

export interface DetectedVideo {
  id: string;
  url: string;
  type: string;
  title: string;
  duration?: number;
  width?: number;
  height?: number;
  quality?: string;
  thumbnail?: string;
  source?: string;
}

// Store intercepted video URLs from network requests
const interceptedVideos: Map<string, DetectedVideo> = new Map();

/**
 * Generate a unique ID for a video
 */
function generateVideoId(url: string): string {
  // Use a hash for longer URLs
  let hash = 0;
  for (let i = 0; i < url.length; i++) {
    const char = url.charCodeAt(i);
    hash = ((hash << 5) - hash) + char;
    hash = hash & hash;
  }
  return Math.abs(hash).toString(36);
}

/**
 * Extract title from URL or page
 */
function extractTitle(url: string, element?: HTMLVideoElement): string {
  // Try to get title from video element attributes
  if (element) {
    const title = element.getAttribute('title') || element.getAttribute('aria-label');
    if (title) return title;

    // Try to find nearby heading or label
    const parent = element.closest('figure, article, section, div');
    if (parent) {
      const heading = parent.querySelector('h1, h2, h3, h4, h5, h6, .title, [class*="title"]');
      if (heading?.textContent) return heading.textContent.trim();
    }
  }

  // Use page title as fallback
  const pageTitle = document.title || 'Untitled Video';

  // Clean up common suffixes
  return pageTitle
    .replace(/\s*[-|]\s*(YouTube|Instagram|Twitter|Facebook|TikTok).*$/i, '')
    .trim() || 'Untitled Video';
}

/**
 * Determine video quality from dimensions
 */
function getQualityLabel(width?: number, height?: number): string {
  if (!width || !height) return 'Unknown';

  const maxDim = Math.max(width, height);
  if (maxDim >= 2160) return '4K';
  if (maxDim >= 1440) return '1440p';
  if (maxDim >= 1080) return '1080p';
  if (maxDim >= 720) return '720p';
  if (maxDim >= 480) return '480p';
  if (maxDim >= 360) return '360p';
  return '240p';
}

/**
 * Get MIME type from URL or default
 */
function getMimeType(url: string): string {
  const extension = url.split('.').pop()?.toLowerCase().split('?')[0];
  const mimeTypes: Record<string, string> = {
    mp4: 'video/mp4',
    webm: 'video/webm',
    ogg: 'video/ogg',
    ogv: 'video/ogg',
    mov: 'video/quicktime',
    avi: 'video/x-msvideo',
    mkv: 'video/x-matroska',
    m3u8: 'application/x-mpegURL',
    mpd: 'application/dash+xml',
    ts: 'video/mp2t',
  };

  return mimeTypes[extension || ''] || 'video/mp4';
}

/**
 * Check if URL is a valid video URL
 */
function isVideoUrl(url: string): boolean {
  if (!url || url.startsWith('blob:') || url.startsWith('data:')) {
    return false;
  }

  const videoPatterns = [
    /\.(mp4|webm|ogg|ogv|mov|avi|mkv|m4v)(\?|$)/i,
    /\.(m3u8|mpd)(\?|$)/i,
    /video/i,
    /\.ts(\?|$)/i,
    /googlevideo\.com/i,
    /fbcdn.*video/i,
    /cdninstagram.*video/i,
    /tiktokcdn.*video/i,
  ];

  return videoPatterns.some(pattern => pattern.test(url));
}

/**
 * Extract quality from URL patterns
 */
function extractQualityFromUrl(url: string): string | undefined {
  const patterns = [
    /(\d{3,4})p/i,
    /itag=(\d+)/i,
    /quality[=_](\w+)/i,
    /res[=_](\d+)/i,
  ];

  for (const pattern of patterns) {
    const match = url.match(pattern);
    if (match) {
      const val = match[1];
      if (/^\d+$/.test(val)) {
        const num = parseInt(val, 10);
        if (num >= 2160) return '4K';
        if (num >= 1440) return '1440p';
        if (num >= 1080) return '1080p';
        if (num >= 720) return '720p';
        if (num >= 480) return '480p';
        if (num >= 360) return '360p';
        return `${num}p`;
      }
      return val;
    }
  }
  return undefined;
}

/**
 * Detect videos from HTML5 video elements
 */
function detectVideoElements(): DetectedVideo[] {
  const videos: DetectedVideo[] = [];
  const videoElements = document.querySelectorAll('video');

  videoElements.forEach((video) => {
    const sources: string[] = [];

    // Direct src attribute
    if (video.src) sources.push(video.src);

    // Current src (might be different from attribute)
    if (video.currentSrc && video.currentSrc !== video.src) {
      sources.push(video.currentSrc);
    }

    // Source elements
    video.querySelectorAll('source').forEach((source) => {
      if (source.src) sources.push(source.src);
    });

    // Process each source
    sources.forEach((src) => {
      if (isVideoUrl(src)) {
        videos.push({
          id: generateVideoId(src),
          url: src,
          type: getMimeType(src),
          title: extractTitle(src, video),
          duration: isFinite(video.duration) ? video.duration : undefined,
          width: video.videoWidth || undefined,
          height: video.videoHeight || undefined,
          quality: extractQualityFromUrl(src) || getQualityLabel(video.videoWidth, video.videoHeight),
          thumbnail: video.poster || undefined,
          source: 'video-element',
        });
      }
    });
  });

  return videos;
}

/**
 * Detect videos from Open Graph and meta tags
 */
function detectMetaVideos(): DetectedVideo[] {
  const videos: DetectedVideo[] = [];

  // Open Graph video tags
  const ogVideo = document.querySelector('meta[property="og:video"]');
  const ogVideoSecure = document.querySelector('meta[property="og:video:secure_url"]');
  const ogVideoType = document.querySelector('meta[property="og:video:type"]');
  const ogTitle = document.querySelector('meta[property="og:title"]');
  const ogImage = document.querySelector('meta[property="og:image"]');

  const videoUrl = ogVideoSecure?.getAttribute('content') || ogVideo?.getAttribute('content');

  if (videoUrl && isVideoUrl(videoUrl)) {
    videos.push({
      id: generateVideoId(videoUrl),
      url: videoUrl,
      type: ogVideoType?.getAttribute('content') || getMimeType(videoUrl),
      title: ogTitle?.getAttribute('content') || extractTitle(videoUrl),
      thumbnail: ogImage?.getAttribute('content') || undefined,
      source: 'og-meta',
    });
  }

  // Twitter video tags
  const twitterVideo = document.querySelector('meta[name="twitter:player:stream"]');
  if (twitterVideo?.getAttribute('content')) {
    const url = twitterVideo.getAttribute('content')!;
    if (isVideoUrl(url)) {
      videos.push({
        id: generateVideoId(url),
        url,
        type: getMimeType(url),
        title: document.querySelector('meta[name="twitter:title"]')?.getAttribute('content') || extractTitle(url),
        thumbnail: document.querySelector('meta[name="twitter:image"]')?.getAttribute('content') || undefined,
        source: 'twitter-meta',
      });
    }
  }

  return videos;
}

/**
 * Detect videos from JSON-LD structured data
 */
function detectJsonLdVideos(): DetectedVideo[] {
  const videos: DetectedVideo[] = [];
  const scripts = document.querySelectorAll('script[type="application/ld+json"]');

  scripts.forEach((script) => {
    try {
      const data = JSON.parse(script.textContent || '');
      const items = Array.isArray(data) ? data : [data];

      const processItem = (item: Record<string, unknown>) => {
        if (item['@type'] === 'VideoObject') {
          const contentUrl = item.contentUrl as string;
          const embedUrl = item.embedUrl as string;
          const url = contentUrl || embedUrl;

          if (url && isVideoUrl(url)) {
            videos.push({
              id: generateVideoId(url),
              url,
              type: getMimeType(url),
              title: (item.name as string) || extractTitle(url),
              duration: item.duration ? parseDuration(item.duration as string) : undefined,
              thumbnail: (item.thumbnailUrl as string) || undefined,
              source: 'json-ld',
            });
          }
        }

        // Check nested items
        if (item['@graph'] && Array.isArray(item['@graph'])) {
          (item['@graph'] as Record<string, unknown>[]).forEach(processItem);
        }
      };

      items.forEach(processItem);
    } catch {
      // Invalid JSON
    }
  });

  return videos;
}

/**
 * Parse ISO 8601 duration to seconds
 */
function parseDuration(duration: string): number | undefined {
  const match = duration.match(/PT(?:(\d+)H)?(?:(\d+)M)?(?:(\d+)S)?/);
  if (!match) return undefined;

  const hours = parseInt(match[1] || '0', 10);
  const minutes = parseInt(match[2] || '0', 10);
  const seconds = parseInt(match[3] || '0', 10);

  return hours * 3600 + minutes * 60 + seconds;
}

/**
 * Site-specific: Detect Instagram videos
 */
function detectInstagramVideos(): DetectedVideo[] {
  const videos: DetectedVideo[] = [];
  const hostname = window.location.hostname;

  if (!hostname.includes('instagram.com')) return videos;

  // Try to find video in page data
  const scripts = document.querySelectorAll('script');
  scripts.forEach((script) => {
    const content = script.textContent || '';

    // Look for video_url in various data structures
    const patterns = [
      /"video_url"\s*:\s*"([^"]+)"/g,
      /"playback_url"\s*:\s*"([^"]+)"/g,
      /video_versions.*?"url"\s*:\s*"([^"]+)"/g,
    ];

    patterns.forEach((pattern) => {
      let match;
      while ((match = pattern.exec(content)) !== null) {
        try {
          // Decode escaped URL
          const url = match[1].replace(/\\u0026/g, '&').replace(/\\/g, '');
          if (url && isVideoUrl(url)) {
            videos.push({
              id: generateVideoId(url),
              url,
              type: 'video/mp4',
              title: extractTitle(url),
              quality: extractQualityFromUrl(url),
              source: 'instagram',
            });
          }
        } catch {
          // Invalid URL
        }
      }
    });
  });

  return videos;
}

/**
 * Site-specific: Detect Twitter/X videos
 */
function detectTwitterVideos(): DetectedVideo[] {
  const videos: DetectedVideo[] = [];
  const hostname = window.location.hostname;

  if (!hostname.includes('twitter.com') && !hostname.includes('x.com')) return videos;

  const scripts = document.querySelectorAll('script');
  scripts.forEach((script) => {
    const content = script.textContent || '';

    // Look for video variants
    const pattern = /"url"\s*:\s*"(https:[^"]*video[^"]*\.mp4[^"]*)"/g;
    let match;
    while ((match = pattern.exec(content)) !== null) {
      try {
        const url = match[1].replace(/\\/g, '');
        if (isVideoUrl(url)) {
          videos.push({
            id: generateVideoId(url),
            url,
            type: 'video/mp4',
            title: extractTitle(url),
            quality: extractQualityFromUrl(url),
            source: 'twitter',
          });
        }
      } catch {
        // Invalid URL
      }
    }
  });

  return videos;
}

/**
 * Site-specific: Detect TikTok videos
 */
function detectTikTokVideos(): DetectedVideo[] {
  const videos: DetectedVideo[] = [];
  const hostname = window.location.hostname;

  if (!hostname.includes('tiktok.com')) return videos;

  const scripts = document.querySelectorAll('script');
  scripts.forEach((script) => {
    const content = script.textContent || '';

    // Look for playAddr or downloadAddr
    const patterns = [
      /"playAddr"\s*:\s*"([^"]+)"/g,
      /"downloadAddr"\s*:\s*"([^"]+)"/g,
    ];

    patterns.forEach((pattern) => {
      let match;
      while ((match = pattern.exec(content)) !== null) {
        try {
          const url = decodeURIComponent(match[1].replace(/\\u002F/g, '/').replace(/\\/g, ''));
          if (url && (url.includes('.mp4') || url.includes('tiktokcdn'))) {
            videos.push({
              id: generateVideoId(url),
              url,
              type: 'video/mp4',
              title: extractTitle(url),
              source: 'tiktok',
            });
          }
        } catch {
          // Invalid URL
        }
      }
    });
  });

  return videos;
}

/**
 * Detect videos from network requests (requires background script support)
 */
export function addInterceptedVideo(video: DetectedVideo): void {
  interceptedVideos.set(video.id, video);
}

/**
 * Get all intercepted videos
 */
export function getInterceptedVideos(): DetectedVideo[] {
  return Array.from(interceptedVideos.values());
}

/**
 * Clear intercepted videos
 */
export function clearInterceptedVideos(): void {
  interceptedVideos.clear();
}

/**
 * Remove duplicate videos by URL
 */
function deduplicateVideos(videos: DetectedVideo[]): DetectedVideo[] {
  const seen = new Map<string, DetectedVideo>();

  videos.forEach((video) => {
    // Normalize URL for comparison
    const normalizedUrl = video.url.split('?')[0];

    if (!seen.has(normalizedUrl)) {
      seen.set(normalizedUrl, video);
    } else {
      // Prefer videos with more metadata
      const existing = seen.get(normalizedUrl)!;
      if ((video.quality && !existing.quality) ||
          (video.duration && !existing.duration) ||
          (video.thumbnail && !existing.thumbnail)) {
        seen.set(normalizedUrl, { ...existing, ...video });
      }
    }
  });

  return Array.from(seen.values());
}

/**
 * Main function to detect all videos on the page
 */
export function detectVideos(): DetectedVideo[] {
  const allVideos = [
    ...detectVideoElements(),
    ...detectMetaVideos(),
    ...detectJsonLdVideos(),
    ...detectInstagramVideos(),
    ...detectTwitterVideos(),
    ...detectTikTokVideos(),
    ...getInterceptedVideos(),
  ];

  // Filter out invalid URLs and deduplicate
  const validVideos = allVideos.filter((video) => {
    try {
      new URL(video.url);
      return true;
    } catch {
      return false;
    }
  });

  return deduplicateVideos(validVideos);
}

/**
 * Format duration in seconds to human readable string
 */
export function formatDuration(seconds?: number): string {
  if (!seconds || isNaN(seconds)) return '';

  const hours = Math.floor(seconds / 3600);
  const minutes = Math.floor((seconds % 3600) / 60);
  const secs = Math.floor(seconds % 60);

  if (hours > 0) {
    return `${hours}:${minutes.toString().padStart(2, '0')}:${secs.toString().padStart(2, '0')}`;
  }
  return `${minutes}:${secs.toString().padStart(2, '0')}`;
}

/**
 * Format file size to human readable string
 */
export function formatFileSize(bytes: number): string {
  if (bytes === 0) return '0 Bytes';

  const k = 1024;
  const sizes = ['Bytes', 'KB', 'MB', 'GB'];
  const i = Math.floor(Math.log(bytes) / Math.log(k));

  return parseFloat((bytes / Math.pow(k, i)).toFixed(2)) + ' ' + sizes[i];
}

