/* Video Downloader Popup Styles */

* {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
}

:root {
  --primary-color: #4CAF50;
  --primary-hover: #45a049;
  --secondary-color: #6c757d;
  --secondary-hover: #5a6268;
  --danger-color: #dc3545;
  --background: #ffffff;
  --surface: #f8f9fa;
  --text-primary: #212529;
  --text-secondary: #6c757d;
  --border-color: #dee2e6;
  --shadow: 0 2px 8px rgba(0, 0, 0, 0.1);
}

body {
  font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, Oxygen, Ubuntu, sans-serif;
  font-size: 14px;
  line-height: 1.5;
  color: var(--text-primary);
  background: var(--background);
  width: 360px;
  min-height: 200px;
  max-height: 500px;
  overflow: hidden;
}

.container {
  display: flex;
  flex-direction: column;
  height: 100%;
  max-height: 500px;
}

/* Header */
.header {
  padding: 16px;
  background: var(--primary-color);
  color: white;
  text-align: center;
}

.header h1 {
  font-size: 18px;
  font-weight: 600;
  margin-bottom: 4px;
}

.header .subtitle {
  font-size: 12px;
  opacity: 0.9;
}

/* Main Content */
#main-content {
  flex: 1;
  overflow-y: auto;
  padding: 12px;
}

/* Loading State */
.loading {
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  padding: 40px 20px;
  color: var(--text-secondary);
}

.spinner {
  width: 32px;
  height: 32px;
  border: 3px solid var(--border-color);
  border-top-color: var(--primary-color);
  border-radius: 50%;
  animation: spin 1s linear infinite;
  margin-bottom: 12px;
}

@keyframes spin {
  to {
    transform: rotate(360deg);
  }
}

/* Video List */
.video-list {
  display: flex;
  flex-direction: column;
  gap: 8px;
}

.video-item {
  display: flex;
  align-items: flex-start;
  gap: 12px;
  padding: 12px;
  background: var(--surface);
  border-radius: 8px;
  border: 1px solid var(--border-color);
  transition: box-shadow 0.2s;
}

.video-item:hover {
  box-shadow: var(--shadow);
}

.video-thumbnail {
  width: 80px;
  height: 45px;
  background: var(--border-color);
  border-radius: 4px;
  overflow: hidden;
  flex-shrink: 0;
}

.video-thumbnail img {
  width: 100%;
  height: 100%;
  object-fit: cover;
}

.video-thumbnail-placeholder {
  width: 100%;
  height: 100%;
  display: flex;
  align-items: center;
  justify-content: center;
  color: var(--text-secondary);
}

.video-info {
  flex: 1;
  min-width: 0;
}

.video-title {
  font-weight: 500;
  font-size: 13px;
  margin-bottom: 4px;
  word-wrap: break-word;
  display: -webkit-box;
  -webkit-line-clamp: 2;
  -webkit-box-orient: vertical;
  overflow: hidden;
}

.video-meta {
  display: flex;
  gap: 8px;
  font-size: 11px;
  color: var(--text-secondary);
  margin-bottom: 8px;
}

.video-meta span {
  display: flex;
  align-items: center;
  gap: 4px;
}

.video-actions {
  display: flex;
  gap: 6px;
}

