.btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 4px;
  padding: 6px 12px;
  font-size: 12px;
  font-weight: 500;
  border: none;
  border-radius: 4px;
  cursor: pointer;
  transition: background-color 0.2s, transform 0.1s;
}

.btn:hover {
  transform: translateY(-1px);
}

.btn:active {
  transform: translateY(0);
}

.btn-primary {
  background: var(--primary-color);
  color: white;
}

.btn-primary:hover {
  background: var(--primary-hover);
}

.btn-secondary {
  background: var(--secondary-color);
  color: white;
}

.btn-secondary:hover {
  background: var(--secondary-hover);
}

.btn-small {
  padding: 4px 8px;
  font-size: 11px;
}

.btn:disabled {
  opacity: 0.6;
  cursor: not-allowed;
  transform: none;
}

/* No Videos State */
.no-videos {
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  padding: 40px 20px;
  text-align: center;
  color: var(--text-secondary);
}

.no-videos svg {
  margin-bottom: 16px;
  opacity: 0.5;
}

.no-videos p {
  margin-bottom: 16px;
}

/* Error State */
.error {
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  padding: 40px 20px;
  text-align: center;
  color: var(--danger-color);
}

.error p {
  margin-bottom: 16px;
}

/* Footer */
.footer {
  padding: 8px 16px;
  background: var(--surface);
  border-top: 1px solid var(--border-color);
  text-align: center;
}

.footer p {
  font-size: 10px;
  color: var(--text-secondary);
}

/* Download Progress */
.download-progress {
  width: 100%;
  height: 4px;
  background: var(--border-color);
  border-radius: 2px;
  overflow: hidden;
  margin-top: 8px;
}

.download-progress-bar {
  height: 100%;
  background: var(--primary-color);
  transition: width 0.3s;
}

/* Status Badge */
.status-badge {
  display: inline-block;
  padding: 2px 6px;
