/**
 * Background service worker for the Video Downloader extension
 * Handles download operations, network interception, and extension state
 */

import { type DetectedVideo } from '../utils/video-detector';

interface DownloadOptions {
  video: DetectedVideo;
  filename?: string;
}

interface BadgeState {
  count: number;
  tabId: number;
}

interface DownloadRecord {
  videoId: string;
  url: string;
  timestamp: number;
  status: 'downloading' | 'completed' | 'failed';
}

// Store intercepted videos per tab
const interceptedVideos = new Map<number, Map<string, DetectedVideo>>();
const badgeStates = new Map<number, BadgeState>();
const downloadHistory = new Map<string, DownloadRecord>();

// Video URL patterns to intercept (excluding init segments)
const VIDEO_PATTERNS = [
  /\.(mp4|webm|m4v|mov)(\?|$)/i,
  /googlevideo\.com.*?(video|itag)/i,
  /cdninstagram\.com.*?video/i,
  /video\.twimg\.com/i,
  /tiktokcdn.*?video/i,
  /fbcdn.*?video/i,
];

// Patterns to SKIP (init segments, manifests, etc.)
const SKIP_PATTERNS = [
  /dashinit\.mp4/i,
  /init\.mp4/i,
  /\.m3u8(\?|$)/i,
  /\.mpd(\?|$)/i,
  /manifest/i,
  /\.ts(\?|$)/i,
  /\.m4s(\?|$)/i,
];

export default defineBackground(() => {
  console.log('[Video Downloader] Background service worker started');

  // Intercept network requests to detect video URLs
  setupNetworkInterception();

  // Listen for messages from content scripts and popup
  browser.runtime.onMessage.addListener((message, sender, sendResponse) => {
    if (message.action === 'download') {
      handleDownload(message.options as DownloadOptions)
        .then((downloadId) => sendResponse({ success: true, downloadId }))
        .catch((error) => sendResponse({ success: false, error: error.message }));
      return true;
    }

    if (message.action === 'videosDetected' && sender.tab?.id) {
      updateBadge(sender.tab.id, message.count);
      sendResponse({ received: true });
      return true;
    }

    if (message.action === 'videosUpdated' && sender.tab?.id) {
      sendResponse({ received: true });
      return true;
    }

    if (message.action === 'getBadgeCount') {
      const tabId = message.tabId;
      const state = badgeStates.get(tabId);
      sendResponse({ count: state?.count || 0 });
      return true;
    }

    if (message.action === 'getInterceptedVideos') {
      const tabId = message.tabId;
      const videos = interceptedVideos.get(tabId);
      sendResponse({ videos: videos ? Array.from(videos.values()) : [] });
      return true;
    }

    if (message.action === 'clearInterceptedVideos') {
      const tabId = message.tabId;
      interceptedVideos.delete(tabId);
      sendResponse({ cleared: true });
      return true;
    }

    if (message.action === 'getDownloadStatus') {
      const videoId = message.videoId;
      const record = downloadHistory.get(videoId);
      sendResponse({ status: record?.status || null });
      return true;
    }

    if (message.action === 'getDownloadHistory') {
      const history = Array.from(downloadHistory.values());
      sendResponse({ history });
      return true;
    }

    return false;
  });

  // Clean up state when tab is closed
  browser.tabs.onRemoved.addListener((tabId) => {
    badgeStates.delete(tabId);
    interceptedVideos.delete(tabId);
  });

  // Reset state when tab navigates
  browser.tabs.onUpdated.addListener((tabId, changeInfo) => {
    if (changeInfo.status === 'loading') {
      badgeStates.delete(tabId);
      interceptedVideos.delete(tabId);
      browser.action.setBadgeText({ tabId, text: '' });
    }
  });

  // Monitor download progress
  browser.downloads.onChanged.addListener((delta) => {
    if (delta.state) {
      // Find the download record by download ID
      for (const [videoId, record] of downloadHistory.entries()) {
        // Update status based on download state
        if (delta.state.current === 'complete') {
          downloadHistory.set(videoId, { ...record, status: 'completed' });
        } else if (delta.state.current === 'interrupted') {
          downloadHistory.set(videoId, { ...record, status: 'failed' });
        }
      }
    }
  });
});

/**
 * Set up network request interception using webRequest API
 */
function setupNetworkInterception(): void {
  if (browser.webRequest?.onCompleted) {
    browser.webRequest.onCompleted.addListener(
      (details) => {
        if (details.tabId < 0) return;

        const url = details.url;
        if (isValidVideoUrl(url)) {
          addInterceptedVideo(details.tabId, url, details.type);
        }
      },
      { urls: ['<all_urls>'] },
      []
    );

    browser.webRequest.onBeforeRequest.addListener(
      (details) => {
        if (details.tabId < 0) return;

        const url = details.url;
        if (isValidVideoUrl(url)) {
          addInterceptedVideo(details.tabId, url, details.type);
        }
      },
      { urls: ['<all_urls>'] },
      []
    );
  }
}

/**
 * Check if URL is a valid downloadable video (not an init segment)
 */
function isValidVideoUrl(url: string): boolean {
  if (!url || url.startsWith('blob:') || url.startsWith('data:')) {
    return false;
  }

  // First check if it should be skipped
  if (SKIP_PATTERNS.some(pattern => pattern.test(url))) {
    return false;
  }

  // Then check if it matches video patterns
  if (!VIDEO_PATTERNS.some(pattern => pattern.test(url))) {
    return false;
  }

  // Instagram-specific: Check for duration (full video) vs init segment
  if (url.includes('cdninstagram.com')) {
    if (url.includes('dashinit')) return false;

    // Check for duration_s parameter
    const durationMatch = url.match(/duration_s[":]+(\d+)/);
    if (durationMatch) {
      const duration = parseInt(durationMatch[1], 10);
      return duration > 1;
    }

    // Progressive videos are OK
    if (url.includes('progressive')) return true;

    // Default: skip if no duration found (might be init)
    return false;
  }

  return true;
}

/**
 * Add intercepted video to storage
 */
function addInterceptedVideo(tabId: number, url: string, resourceType: string): void {
  if (!interceptedVideos.has(tabId)) {
    interceptedVideos.set(tabId, new Map());
  }

  const tabVideos = interceptedVideos.get(tabId)!;
  const videoId = generateVideoId(url);

  // Skip if already exists
  if (tabVideos.has(videoId)) return;

  const video: DetectedVideo = {
    id: videoId,
    url,
    type: getMimeType(url),
    title: extractTitleFromUrl(url),
    quality: extractQualityFromUrl(url),
    source: `network-${resourceType}`,
  };

  tabVideos.set(videoId, video);
  console.log(`[Video Downloader] Intercepted: ${url.substring(0, 80)}...`);

  // Update badge count
  updateBadgeFromIntercepted(tabId);
}

/**
 * Update badge based on intercepted videos
 */
async function updateBadgeFromIntercepted(tabId: number): Promise<void> {
  const videos = interceptedVideos.get(tabId);
  const count = videos?.size || 0;

  if (count > 0) {
    await browser.action.setBadgeText({ tabId, text: count.toString() });
    await browser.action.setBadgeBackgroundColor({ tabId, color: '#4CAF50' });
  }
}

/**
 * Generate video ID from URL
 */
function generateVideoId(url: string): string {
  let hash = 0;
  for (let i = 0; i < url.length; i++) {
    const char = url.charCodeAt(i);
    hash = ((hash << 5) - hash) + char;
    hash = hash & hash;
  }
  return Math.abs(hash).toString(36);
}

/**
 * Extract quality from URL
 */
function extractQualityFromUrl(url: string): string | undefined {
  const patterns = [
    /(\d{3,4})p/i,
    /itag=(\d+)/i,
    /quality[=_](\w+)/i,
  ];

  for (const pattern of patterns) {
    const match = url.match(pattern);
    if (match) {
      const val = match[1];
      if (/^\d+$/.test(val)) {
        const num = parseInt(val, 10);
        const itagMap: Record<number, string> = {
          18: '360p', 22: '720p', 37: '1080p', 38: '4K',
          137: '1080p', 136: '720p', 135: '480p', 134: '360p',
          298: '720p60', 299: '1080p60', 303: '1080p60', 302: '720p60',
        };
        if (itagMap[num]) return itagMap[num];
        if (num >= 2160) return '4K';
        if (num >= 1080) return '1080p';
        if (num >= 720) return '720p';
        if (num >= 480) return '480p';
        return `${num}p`;
      }
      return val;
    }
  }
  return undefined;
}

/**
 * Extract title from URL
 */
function extractTitleFromUrl(url: string): string {
  try {
    const urlObj = new URL(url);
    const pathname = urlObj.pathname;
    const filename = pathname.split('/').pop() || '';
    const name = filename.replace(/\.[^.]+$/, '').replace(/[-_]/g, ' ');
    if (name && name.length > 3) return name;
  } catch {
    // Invalid URL
  }
  return 'Video';
}

/**
 * Get MIME type from URL
 */
function getMimeType(url: string): string {
  const extension = url.split('.').pop()?.toLowerCase().split('?')[0];
  const mimeTypes: Record<string, string> = {
    mp4: 'video/mp4',
    webm: 'video/webm',
    m4v: 'video/mp4',
    mov: 'video/quicktime',
  };
  return mimeTypes[extension || ''] || 'video/mp4';
}

/**
 * Update the extension badge with video count
 */
async function updateBadge(tabId: number, count: number): Promise<void> {
  badgeStates.set(tabId, { count, tabId });

  await browser.action.setBadgeText({
    tabId,
    text: count > 0 ? count.toString() : '',
  });

  await browser.action.setBadgeBackgroundColor({
    tabId,
    color: count > 0 ? '#4CAF50' : '#9E9E9E',
  });
}

/**
 * Handle video download request
 */
async function handleDownload(options: DownloadOptions): Promise<number> {
  const { video, filename } = options;

  // Generate slug filename from title
  const slugTitle = slugify(filename || video.title);
  const extension = getFileExtension(video.url, video.type);
  const finalFilename = `${slugTitle || 'video'}.${extension}`;

  // Track download status
  downloadHistory.set(video.id, {
    videoId: video.id,
    url: video.url,
    timestamp: Date.now(),
    status: 'downloading',
  });

  try {
    const downloadId = await browser.downloads.download({
      url: video.url,
      filename: finalFilename,
      saveAs: true,
    });

    console.log(`[Video Downloader] Started download: ${finalFilename} (ID: ${downloadId})`);
    return downloadId;
  } catch (error) {
    downloadHistory.set(video.id, {
      videoId: video.id,
      url: video.url,
      timestamp: Date.now(),
      status: 'failed',
    });
    console.error('[Video Downloader] Download failed:', error);
    throw error;
  }
}

/**
 * Convert string to URL-friendly slug
 */
function slugify(text: string): string {
  return text
    .toString()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '') // Remove accents
    .toLowerCase()
    .trim()
    .replace(/[^a-z0-9\s-]/g, '') // Remove non-alphanumeric
    .replace(/\s+/g, '-') // Replace spaces with -
    .replace(/-+/g, '-') // Replace multiple - with single -
    .replace(/^-+|-+$/g, '') // Remove leading/trailing -
    .slice(0, 80); // Limit length
}

/**
 * Get appropriate file extension from URL or MIME type
 */
function getFileExtension(url: string, mimeType: string): string {
  const urlExtension = url.split('.').pop()?.split('?')[0]?.toLowerCase();
  if (urlExtension && ['mp4', 'webm', 'ogg', 'mov', 'avi', 'mkv', 'm4v'].includes(urlExtension)) {
    return urlExtension;
  }

  const mimeToExt: Record<string, string> = {
    'video/mp4': 'mp4',
    'video/webm': 'webm',
    'video/ogg': 'ogg',
    'video/quicktime': 'mov',
    'video/x-msvideo': 'avi',
    'video/x-matroska': 'mkv',
  };

  return mimeToExt[mimeType] || 'mp4';
}

// Type declaration for WXT's defineBackground
declare function defineBackground(fn: () => void): void;

