   186→    const durationMatch = url.match(/duration_s[":]+(\d+)/);
   187→    if (durationMatch) {
   188→      const duration = parseInt(durationMatch[1], 10);
   189→      return duration > 1; // Must be longer than 1 second
   190→    }
   191→    // If URL has progressive in it, it's likely a full video
   192→    if (url.includes('progressive')) {
   193→      return true;
   194→    }
   195→  }
   196→
   197→  return true;
   198→}
   199→
   200→/**
   201→ * Extract quality from URL patterns
   202→ */
   203→function extractQualityFromUrl(url: string): string | undefined {
   204→  // Check for resolution in URL
   205→  const resMatch = url.match(/[._](\d{3,4})p[._]/i) || url.match(/\.(\d{3,4})\./);
   206→  if (resMatch) {
   207→    const res = parseInt(resMatch[1], 10);
   208→    if (res >= 2160) return '4K';
   209→    if (res >= 1440) return '1440p';
   210→    if (res >= 1080) return '1080p';
   211→    if (res >= 720) return '720p';
   212→    if (res >= 480) return '480p';
   213→    if (res >= 360) return '360p';
   214→    return `${res}p`;
   215→  }
   216→
   217→  // Instagram: Try to extract from base64 encoded metadata
   218→  if (url.includes('cdninstagram.com')) {
   219→    if (url.includes('720')) return '720p';
   220→    if (url.includes('1080')) return '1080p';
   221→    if (url.includes('480')) return '480p';
   222→  }
   223→
   224→  return undefined;
   225→}
   226→
   227→/**
   228→ * Extract thumbnail URL from page
   229→ */
   230→function extractThumbnail(): string | undefined {
   231→  // Try og:image first
   232→  const ogImage = document.querySelector('meta[property="og:image"]');
   233→  if (ogImage?.getAttribute('content')) {
   234→    return ogImage.getAttribute('content')!;
   235→  }
   236→
   237→  // Try twitter:image
   238→  const twitterImage = document.querySelector('meta[name="twitter:image"]');
   239→  if (twitterImage?.getAttribute('content')) {
   240→    return twitterImage.getAttribute('content')!;
   241→  }
   242→
   243→  // Try video poster
   244→  const video = document.querySelector('video[poster]');
   245→  if (video?.getAttribute('poster')) {
   246→    return video.getAttribute('poster')!;
   247→  }
   248→
   249→  return undefined;
