   252→/**
   253→ * Detect videos from HTML5 video elements
   254→ */
   255→function detectVideoElements(): DetectedVideo[] {
   256→  const videos: DetectedVideo[] = [];
   257→  const videoElements = document.querySelectorAll('video');
   258→  const pageTitle = extractPageTitle();
   259→  const thumbnail = extractThumbnail();
   260→
   261→  videoElements.forEach((video) => {
   262→    const sources: string[] = [];
   263→
   264→    if (video.src) sources.push(video.src);
   265→    if (video.currentSrc && video.currentSrc !== video.src) {
   266→      sources.push(video.currentSrc);
   267→    }
   268→
   269→    video.querySelectorAll('source').forEach((source) => {
   270→      if (source.src) sources.push(source.src);
   271→    });
   272→
   273→    sources.forEach((src) => {
   274→      if (isValidVideoUrl(src) && isFullVideo(src)) {
   275→        videos.push({
   276→          id: generateVideoId(src),
   277→          url: src,
   278→          type: getMimeType(src),
   279→          title: pageTitle,
   280→          duration: isFinite(video.duration) ? video.duration : undefined,
   281→          width: video.videoWidth || undefined,
   282→          height: video.videoHeight || undefined,
   283→          quality: extractQualityFromUrl(src) || getQualityLabel(video.videoWidth, video.videoHeight),
   284→          thumbnail: video.poster || thumbnail,
   285→          source: 'video-element',
   286→        });
   287→      }
   288→    });
   289→  });
   290→
   291→  return videos;
   292→}
