   294→/**
   295→ * Detect videos from Open Graph and meta tags
   296→ */
   297→function detectMetaVideos(): DetectedVideo[] {
   298→  const videos: DetectedVideo[] = [];
   299→  const pageTitle = extractPageTitle();
   300→  const thumbnail = extractThumbnail();
   301→
   302→  const ogVideo = document.querySelector('meta[property="og:video"]');
   303→  const ogVideoSecure = document.querySelector('meta[property="og:video:secure_url"]');
   304→  const ogVideoType = document.querySelector('meta[property="og:video:type"]');
   305→
   306→  const videoUrl = ogVideoSecure?.getAttribute('content') || ogVideo?.getAttribute('content');
   307→
   308→  if (videoUrl && isValidVideoUrl(videoUrl) && isFullVideo(videoUrl)) {
   309→    videos.push({
   310→      id: generateVideoId(videoUrl),
   311→      url: videoUrl,
   312→      type: ogVideoType?.getAttribute('content') || getMimeType(videoUrl),
   313→      title: pageTitle,
   314→      thumbnail,
   315→      source: 'og-meta',
   316→    });
   317→  }
   318→
   319→  return videos;
