   322→/**
   323→ * Detect videos from JSON-LD structured data
   324→ */
   325→function detectJsonLdVideos(): DetectedVideo[] {
   326→  const videos: DetectedVideo[] = [];
   327→  const scripts = document.querySelectorAll('script[type="application/ld+json"]');
   328→  const pageTitle = extractPageTitle();
   329→
   330→  scripts.forEach((script) => {
   331→    try {
   332→      const data = JSON.parse(script.textContent || '');
   333→      const items = Array.isArray(data) ? data : [data];
   334→
   335→      const processItem = (item: Record<string, unknown>) => {
   336→        if (item['@type'] === 'VideoObject') {
   337→          const contentUrl = item.contentUrl as string;
   338→          const embedUrl = item.embedUrl as string;
   339→          const url = contentUrl || embedUrl;
   340→
   341→          if (url && isValidVideoUrl(url) && isFullVideo(url)) {
   342→            videos.push({
   343→              id: generateVideoId(url),
   344→              url,
   345→              type: getMimeType(url),
   346→              title: (item.name as string) || pageTitle,
   347→              duration: item.duration ? parseDuration(item.duration as string) : undefined,
   348→              thumbnail: (item.thumbnailUrl as string) || undefined,
   349→              source: 'json-ld',
   350→            });
   351→          }
   352→        }
   353→
   354→        if (item['@graph'] && Array.isArray(item['@graph'])) {
   355→          (item['@graph'] as Record<string, unknown>[]).forEach(processItem);
   356→        }
   357→      };
   358→
   359→      items.forEach(processItem);
   360→    } catch {
   361→      // Invalid JSON
   362→    }
   363→  });
   364→
   365→  return videos;
   366→}
   367→
   368→/**
   369→ * Parse ISO 8601 duration to seconds
   370→ */
   371→function parseDuration(duration: string): number | undefined {
   372→  const match = duration.match(/PT(?:(\d+)H)?(?:(\d+)M)?(?:(\d+)S)?/);
   373→  if (!match) return undefined;
   374→
   375→  const hours = parseInt(match[1] || '0', 10);
   376→  const minutes = parseInt(match[2] || '0', 10);
   377→  const seconds = parseInt(match[3] || '0', 10);
   378→
   379→  return hours * 3600 + minutes * 60 + seconds;
   380→}
   381→
   382→/**
   383→ * Site-specific: Detect Instagram videos
   384→ */
   385→function detectInstagramVideos(): DetectedVideo[] {
   386→  const videos: DetectedVideo[] = [];
   387→  const hostname = window.location.hostname;
   388→
   389→  if (!hostname.includes('instagram.com')) return videos;
   390→
   391→  const pageTitle = extractPageTitle();
   392→  const thumbnail = extractThumbnail();
   393→
   394→  const scripts = document.querySelectorAll('script');
   395→  scripts.forEach((script) => {
   396→    const content = script.textContent || '';
   397→
   398→    // Look for video_url patterns - but filter out init segments
   399→    const patterns = [
   400→      /"video_url"\s*:\s*"([^"]+)"/g,
   401→      /"playback_url"\s*:\s*"([^"]+)"/g,
   402→    ];
   403→
   404→    patterns.forEach((pattern) => {
   405→      let match;
   406→      while ((match = pattern.exec(content)) !== null) {
   407→        try {
   408→          const url = match[1]
   409→            .replace(/\\u0026/g, '&')
   410→            .replace(/\\u002F/g, '/')
   411→            .replace(/\\/g, '');
   412→
   413→          // Filter: Must be a valid video and not an init segment
   414→          if (url && isValidVideoUrl(url) && isFullVideo(url)) {
   415→            videos.push({
   416→              id: generateVideoId(url),
   417→              url,
   418→              type: 'video/mp4',
   419→              title: pageTitle,
   420→              quality: extractQualityFromUrl(url) || '720p',
   421→              thumbnail,
   422→              source: 'instagram',
   423→            });
   424→          }
   425→        } catch {
   426→          // Invalid URL
   427→        }
   428→      }
   429→    });
   430→  });
   431→
   432→  return videos;
   433→}
   434→
   435→/**
   436→ * Site-specific: Detect Twitter/X videos
   437→ */
   438→function detectTwitterVideos(): DetectedVideo[] {
   439→  const videos: DetectedVideo[] = [];
   440→  const hostname = window.location.hostname;
   441→
   442→  if (!hostname.includes('twitter.com') && !hostname.includes('x.com')) return videos;
   443→
   444→  const pageTitle = extractPageTitle();
   445→  const thumbnail = extractThumbnail();
   446→
   447→  const scripts = document.querySelectorAll('script');
   448→  scripts.forEach((script) => {
   449→    const content = script.textContent || '';
   450→
   451→    const pattern = /"url"\s*:\s*"(https:[^"]*video[^"]*\.mp4[^"]*)"/g;
   452→    let match;
   453→    while ((match = pattern.exec(content)) !== null) {
   454→      try {
   455→        const url = match[1].replace(/\\/g, '');
   456→        if (isValidVideoUrl(url)) {
   457→          videos.push({
   458→            id: generateVideoId(url),
   459→            url,
   460→            type: 'video/mp4',
   461→            title: pageTitle,
   462→            quality: extractQualityFromUrl(url),
   463→            thumbnail,
   464→            source: 'twitter',
   465→          });
   466→        }
   467→      } catch {
   468→        // Invalid URL
   469→      }
   470→    }
   471→  });
   472→
   473→  return videos;
   474→}
   475→
   476→/**
   477→ * Site-specific: Detect TikTok videos
   478→ */
   479→function detectTikTokVideos(): DetectedVideo[] {
   480→  const videos: DetectedVideo[] = [];
   481→  const hostname = window.location.hostname;
   482→
   483→  if (!hostname.includes('tiktok.com')) return videos;
   484→
   485→  const pageTitle = extractPageTitle();
   486→  const thumbnail = extractThumbnail();
   487→
   488→  const scripts = document.querySelectorAll('script');
   489→  scripts.forEach((script) => {
   490→    const content = script.textContent || '';
   491→
   492→    const patterns = [
   493→      /"playAddr"\s*:\s*"([^"]+)"/g,
   494→      /"downloadAddr"\s*:\s*"([^"]+)"/g,
   495→    ];
   496→
   497→    patterns.forEach((pattern) => {
   498→      let match;
   499→      while ((match = pattern.exec(content)) !== null) {
   500→        try {
   501→          const url = decodeURIComponent(match[1].replace(/\\u002F/g, '/').replace(/\\/g, ''));
   502→          if (url && (url.includes('.mp4') || url.includes('tiktokcdn'))) {
   503→            videos.push({
   504→              id: generateVideoId(url),
   505→              url,
   506→              type: 'video/mp4',
   507→              title: pageTitle,
   508→              thumbnail,
   509→              source: 'tiktok',
   510→            });
   511→          }
   512→        } catch {
   513→          // Invalid URL
   514→        }
   515→      }
   516→    });
   517→  });
   518→
   519→  return videos;
