   521→
   522→/**
   523→ * Add intercepted video
   524→ */
   525→export function addInterceptedVideo(video: DetectedVideo): void {
   526→  interceptedVideos.set(video.id, video);
   527→}
   528→
   529→/**
   530→ * Get all intercepted videos
   531→ */
   532→export function getInterceptedVideos(): DetectedVideo[] {
   533→  return Array.from(interceptedVideos.values());
   534→}
   535→
   536→/**
   537→ * Clear intercepted videos
   538→ */
   539→export function clearInterceptedVideos(): void {
   540→  interceptedVideos.clear();
   541→}
   542→
   543→/**
   544→ * Remove duplicate videos by URL
   545→ */
   546→function deduplicateVideos(videos: DetectedVideo[]): DetectedVideo[] {
   547→  const seen = new Map<string, DetectedVideo>();
   548→
   549→  videos.forEach((video) => {
   550→    // Normalize URL for comparison (remove query params for dedup)
   551→    const normalizedUrl = video.url.split('?')[0];
   552→
   553→    if (!seen.has(normalizedUrl)) {
   554→      seen.set(normalizedUrl, video);
   555→    } else {
   556→      const existing = seen.get(normalizedUrl)!;
   557→      // Prefer videos with better metadata
   558→      if ((video.quality && !existing.quality) ||
   559→          (video.duration && !existing.duration) ||
   560→          (video.thumbnail && !existing.thumbnail) ||
   561→          (video.title !== 'Instagram' && existing.title === 'Instagram')) {
   562→        seen.set(normalizedUrl, { ...existing, ...video });
   563→      }
   564→    }
   565→  });
   566→
   567→  return Array.from(seen.values());
   568→}
   569→
   570→/**
   571→ * Main function to detect all videos on the page
   572→ */
   573→export function detectVideos(): DetectedVideo[] {
   574→  const allVideos = [
   575→    ...detectVideoElements(),
   576→    ...detectMetaVideos(),
   577→    ...detectJsonLdVideos(),
   578→    ...detectInstagramVideos(),
   579→    ...detectTwitterVideos(),
   580→    ...detectTikTokVideos(),
   581→    ...getInterceptedVideos(),
   582→  ];
   583→
   584→  // Filter and validate
   585→  const validVideos = allVideos.filter((video) => {
   586→    try {
   587→      new URL(video.url);
   588→      return isFullVideo(video.url);
   589→    } catch {
   590→      return false;
   591→    }
   592→  });
   593→
   594→  return deduplicateVideos(validVideos);
   595→}
   596→
   597→/**
   598→ * Format duration in seconds to human readable string
   599→ */
   600→export function formatDuration(seconds?: number): string {
   601→  if (!seconds || isNaN(seconds)) return '';
   602→
   603→  const hours = Math.floor(seconds / 3600);
   604→  const minutes = Math.floor((seconds % 3600) / 60);
   605→  const secs = Math.floor(seconds % 60);
   606→
   607→  if (hours > 0) {
   608→    return `${hours}:${minutes.toString().padStart(2, '0')}:${secs.toString().padStart(2, '0')}`;
   609→  }
   610→  return `${minutes}:${secs.toString().padStart(2, '0')}`;
   611→}
   612→
   613→/**
   614→ * Format file size to human readable string
   615→ */
   616→export function formatFileSize(bytes: number): string {
   617→  if (bytes === 0) return '0 Bytes';
   618→
   619→  const k = 1024;
   620→  const sizes = ['Bytes', 'KB', 'MB', 'GB'];
   621→  const i = Math.floor(Math.log(bytes) / Math.log(k));
   622→
   623→  return parseFloat((bytes / Math.pow(k, i)).toFixed(2)) + ' ' + sizes[i];
   624→}
   625→
   626→/**
   627→ * Convert string to URL-friendly slug
   628→ */
   629→export function slugify(text: string): string {
   630→  return text
   631→    .toString()
   632→    .normalize('NFD')
   633→    .replace(/[\u0300-\u036f]/g, '') // Remove accents
   634→    .toLowerCase()
   635→    .trim()
   636→    .replace(/[^a-z0-9\s-]/g, '') // Remove non-alphanumeric
   637→    .replace(/\s+/g, '-') // Replace spaces with -
   638→    .replace(/-+/g, '-') // Replace multiple - with single -
   639→    .replace(/^-+|-+$/g, '') // Remove leading/trailing -
   640→    .slice(0, 80); // Limit length
   641→}
