/**
 * Content script for video detection on web pages
 * Runs in the context of web pages to find and extract video information
 */

import { detectVideos, type DetectedVideo } from '../utils/video-detector';

export default defineContentScript({
  matches: ['<all_urls>'],
  runAt: 'document_idle',

  main() {
    console.log('[Video Downloader] Content script loaded');

    // Listen for messages from popup or background
    browser.runtime.onMessage.addListener((message, _sender, sendResponse) => {
      if (message.action === 'detectVideos') {
        const videos = detectVideos();
        console.log('[Video Downloader] Detected videos:', videos);
        sendResponse({ videos });
        return true;
      }

      if (message.action === 'ping') {
        sendResponse({ status: 'ready' });
        return true;
      }

      return false;
    });

    // Observe for dynamically loaded videos
    const observer = new MutationObserver((mutations) => {
      let hasNewVideos = false;

      mutations.forEach((mutation) => {
        mutation.addedNodes.forEach((node) => {
          if (node instanceof HTMLElement) {
            if (node.tagName === 'VIDEO' || node.querySelector('video')) {
              hasNewVideos = true;
            }
          }
        });
      });

      if (hasNewVideos) {
        // Notify background about potential new videos
        browser.runtime.sendMessage({ action: 'videosUpdated' }).catch(() => {
          // Background might not be ready
        });
      }
    });

    observer.observe(document.body, {
      childList: true,
      subtree: true,
    });

    // Initial detection and notification
    setTimeout(() => {
      const videos = detectVideos();
      if (videos.length > 0) {
        browser.runtime.sendMessage({
          action: 'videosDetected',
          count: videos.length,
        }).catch(() => {
          // Background might not be ready
        });
      }
    }, 1000);
  },
});

// Type declaration for WXT's defineContentScript
declare function defineContentScript(options: {
  matches: string[];
  runAt?: 'document_start' | 'document_end' | 'document_idle';
  main: () => void;
}): {
  matches: string[];
  runAt?: 'document_start' | 'document_end' | 'document_idle';
  main: () => void;
};

