/**
 * Simple tests for video-detector utility functions
 * Run with: bun test
 */

import { describe, expect, test } from 'bun:test';
import { slugify, formatDuration, formatFileSize } from '../utils/video-detector';

describe('slugify', () => {
  test('converts basic text to slug', () => {
    expect(slugify('Hello World')).toBe('hello-world');
  });

  test('removes special characters', () => {
    expect(slugify('Video @user #hashtag')).toBe('video-user-hashtag');
  });

  test('handles accented characters', () => {
    expect(slugify('Café Résumé')).toBe('cafe-resume');
  });

  test('limits length to 80 chars', () => {
    const longText = 'a'.repeat(100);
    expect(slugify(longText).length).toBeLessThanOrEqual(80);
  });

  test('removes leading/trailing dashes', () => {
    expect(slugify('--test--')).toBe('test');
  });
});

describe('formatDuration', () => {
  test('formats seconds only', () => {
    expect(formatDuration(45)).toBe('0:45');
  });

  test('formats minutes and seconds', () => {
    expect(formatDuration(125)).toBe('2:05');
  });

  test('formats hours, minutes, and seconds', () => {
    expect(formatDuration(3665)).toBe('1:01:05');
  });

  test('returns empty string for undefined', () => {
    expect(formatDuration(undefined)).toBe('');
  });

  test('returns empty string for NaN', () => {
    expect(formatDuration(NaN)).toBe('');
  });
});

describe('formatFileSize', () => {
  test('formats bytes', () => {
    expect(formatFileSize(500)).toBe('500 Bytes');
  });

  test('formats kilobytes', () => {
    expect(formatFileSize(2048)).toBe('2 KB');
  });

  test('formats megabytes', () => {
    expect(formatFileSize(1048576)).toBe('1 MB');
  });

  test('formats gigabytes', () => {
    expect(formatFileSize(1073741824)).toBe('1 GB');
  });

  test('returns 0 Bytes for 0', () => {
    expect(formatFileSize(0)).toBe('0 Bytes');
  });
});

