/**
 * Video detection utilities for finding video elements and sources on web pages
 * Supports detection via DOM, meta tags, network interception, and site-specific extractors
 */

export interface DetectedVideo {
  id: string;
  url: string;
  type: string;
  title: string;
  duration?: number;
  width?: number;
  height?: number;
  quality?: string;
  thumbnail?: string;
  source?: string;
}

// Store intercepted video URLs from network requests
const interceptedVideos: Map<string, DetectedVideo> = new Map();

/**
 * Generate a unique ID for a video
 */
function generateVideoId(url: string): string {
  let hash = 0;
  for (let i = 0; i < url.length; i++) {
    const char = url.charCodeAt(i);
    hash = ((hash << 5) - hash) + char;
    hash = hash & hash;
  }
  return Math.abs(hash).toString(36);
}

/**
 * Extract title from the page based on site
 */
function extractPageTitle(): string {
  const hostname = window.location.hostname;

  // YouTube-specific title extraction
  if (hostname.includes('youtube.com') || hostname.includes('youtu.be')) {
    // For shorts, get the title from the page
    const ytTitle = document.querySelector('yt-formatted-string.ytd-watch-metadata, h1.ytd-watch-metadata yt-formatted-string, #title h1 yt-formatted-string');
    if (ytTitle?.textContent?.trim()) {
      return ytTitle.textContent.trim().slice(0, 80);
    }

    // Try shorts-specific selectors
    const shortsTitle = document.querySelector('[class*="shorts"] h2, ytd-reel-video-renderer h2');
    if (shortsTitle?.textContent?.trim()) {
      return shortsTitle.textContent.trim().slice(0, 80);
    }

    // Fallback to meta description
    const metaDesc = document.querySelector('meta[name="description"]');
    if (metaDesc?.getAttribute('content')) {
      const desc = metaDesc.getAttribute('content')!;
      // Take first sentence or 80 chars
      const firstSentence = desc.split('.')[0].trim();
      if (firstSentence.length > 5) {
        return firstSentence.slice(0, 80);
      }
    }
  }

  // Instagram-specific title extraction
  if (hostname.includes('instagram.com')) {
    // Try to get username and caption
    const usernameEl = document.querySelector('header a[role="link"] span, a[href*="/"] > div > span');
    const captionEl = document.querySelector('h1, span[dir="auto"]');

    let title = '';

    // Get username
    const userLink = document.querySelector('header a[href*="/"]');
    if (userLink) {
      const href = userLink.getAttribute('href');
      if (href) {
        const username = href.replace(/\//g, '');
        if (username && username.length > 0 && username.length < 50) {
          title = `@${username}`;
        }
      }
    }

    // Try to get caption/description
    const metaDesc = document.querySelector('meta[property="og:description"]');
    if (metaDesc) {
      const desc = metaDesc.getAttribute('content');
      if (desc) {
        // Extract first part of caption (before hashtags usually)
        const caption = desc.split(/[#@]/)[0].trim().slice(0, 60);
        if (caption) {
          title = title ? `${title} - ${caption}` : caption;
        }
      }
    }

    if (title) return title;
  }

  // Twitter/X specific
  if (hostname.includes('twitter.com') || hostname.includes('x.com')) {
    const tweetText = document.querySelector('[data-testid="tweetText"]');
    if (tweetText?.textContent) {
      return tweetText.textContent.slice(0, 60).trim();
    }
  }

  // TikTok specific
  if (hostname.includes('tiktok.com')) {
    const descEl = document.querySelector('[data-e2e="browse-video-desc"], [data-e2e="video-desc"]');
    if (descEl?.textContent) {
      return descEl.textContent.slice(0, 60).trim();
    }
  }

  // Generic: Use page title, cleaned up
  const pageTitle = document.title || 'Untitled Video';
  return pageTitle
    .replace(/\s*[-|•·]\s*(YouTube|Instagram|Twitter|Facebook|TikTok|X).*$/i, '')
    .replace(/\s*on\s*(YouTube|Instagram|Twitter|Facebook|TikTok|X)$/i, '')
    .trim()
    .slice(0, 80) || 'Untitled Video';
}

/**
 * Determine video quality from dimensions
 */
function getQualityLabel(width?: number, height?: number): string {
  if (!width || !height) return 'Unknown';

  const maxDim = Math.max(width, height);
  if (maxDim >= 2160) return '4K';
  if (maxDim >= 1440) return '1440p';
  if (maxDim >= 1080) return '1080p';
  if (maxDim >= 720) return '720p';
  if (maxDim >= 480) return '480p';
  if (maxDim >= 360) return '360p';
  return '240p';
}

/**
 * Get MIME type from URL
 */
function getMimeType(url: string): string {
  const extension = url.split('.').pop()?.toLowerCase().split('?')[0];
  const mimeTypes: Record<string, string> = {
    mp4: 'video/mp4',
    webm: 'video/webm',
    ogg: 'video/ogg',
    ogv: 'video/ogg',
    mov: 'video/quicktime',
    avi: 'video/x-msvideo',
    mkv: 'video/x-matroska',
    m3u8: 'application/x-mpegURL',
    mpd: 'application/dash+xml',
    ts: 'video/mp2t',
  };

  return mimeTypes[extension || ''] || 'video/mp4';
}

/**
 * Check if URL is a valid downloadable video URL (not an init segment)
 */
function isValidVideoUrl(url: string): boolean {
  if (!url || url.startsWith('blob:') || url.startsWith('data:')) {
    return false;
  }

  // Skip init segments and manifest files
  const skipPatterns = [
    /dashinit\.mp4/i,
    /init\.mp4/i,
    /\.m3u8(\?|$)/i,
    /\.mpd(\?|$)/i,
    /manifest/i,
    /\.ts(\?|$)/i,
    /\.m4s(\?|$)/i,
  ];

  if (skipPatterns.some(pattern => pattern.test(url))) {
    return false;
  }

  // Must match video patterns
  const videoPatterns = [
    /\.(mp4|webm|ogg|ogv|mov|avi|mkv|m4v)(\?|$)/i,
    /video/i,
    /googlevideo\.com/i,
    /fbcdn.*video/i,
    /cdninstagram.*video/i,
    /tiktokcdn.*video/i,
  ];

  return videoPatterns.some(pattern => pattern.test(url));
}

/**
 * Check if URL is a proper video (not just init segment) based on URL structure
 */
function isFullVideo(url: string): boolean {
  // Instagram: Check for duration_s in the URL (indicates full video, not init)
  if (url.includes('cdninstagram.com')) {
    // Skip dashinit files - these are initialization segments, not full videos
    if (url.includes('dashinit')) {
      return false;
    }
    // Check for duration parameter which indicates it's a real video
    const durationMatch = url.match(/duration_s[":]+(\d+)/);
    if (durationMatch) {
      const duration = parseInt(durationMatch[1], 10);
      return duration > 1; // Must be longer than 1 second
    }
    // If URL has progressive in it, it's likely a full video
    if (url.includes('progressive')) {
      return true;
    }
  }

  return true;
}

/**
 * Extract quality from URL patterns
 */
function extractQualityFromUrl(url: string): string | undefined {
  // Check for resolution in URL
  const resMatch = url.match(/[._](\d{3,4})p[._]/i) || url.match(/\.(\d{3,4})\./);
  if (resMatch) {
    const res = parseInt(resMatch[1], 10);
    if (res >= 2160) return '4K';
    if (res >= 1440) return '1440p';
    if (res >= 1080) return '1080p';
    if (res >= 720) return '720p';
    if (res >= 480) return '480p';
    if (res >= 360) return '360p';
    return `${res}p`;
  }

  // Instagram: Try to extract from base64 encoded metadata
  if (url.includes('cdninstagram.com')) {
    if (url.includes('720')) return '720p';
    if (url.includes('1080')) return '1080p';
    if (url.includes('480')) return '480p';
  }

  return undefined;
}

/**
 * Extract thumbnail URL from page
 */
function extractThumbnail(): string | undefined {
  // Try og:image first
  const ogImage = document.querySelector('meta[property="og:image"]');
  if (ogImage?.getAttribute('content')) {
    return ogImage.getAttribute('content')!;
  }

  // Try twitter:image
  const twitterImage = document.querySelector('meta[name="twitter:image"]');
  if (twitterImage?.getAttribute('content')) {
    return twitterImage.getAttribute('content')!;
  }

  // Try video poster
  const video = document.querySelector('video[poster]');
  if (video?.getAttribute('poster')) {
    return video.getAttribute('poster')!;
  }

  return undefined;
}

/**
 * Detect videos from HTML5 video elements
 */
function detectVideoElements(): DetectedVideo[] {
  const videos: DetectedVideo[] = [];
  const videoElements = document.querySelectorAll('video');
  const pageTitle = extractPageTitle();
  const thumbnail = extractThumbnail();

  videoElements.forEach((video) => {
    const sources: string[] = [];

    if (video.src) sources.push(video.src);
    if (video.currentSrc && video.currentSrc !== video.src) {
      sources.push(video.currentSrc);
    }

    video.querySelectorAll('source').forEach((source) => {
      if (source.src) sources.push(source.src);
    });

    sources.forEach((src) => {
      if (isValidVideoUrl(src) && isFullVideo(src)) {
        videos.push({
          id: generateVideoId(src),
          url: src,
          type: getMimeType(src),
          title: pageTitle,
          duration: isFinite(video.duration) ? video.duration : undefined,
          width: video.videoWidth || undefined,
          height: video.videoHeight || undefined,
          quality: extractQualityFromUrl(src) || getQualityLabel(video.videoWidth, video.videoHeight),
          thumbnail: video.poster || thumbnail,
          source: 'video-element',
        });
      }
    });
  });

  return videos;
}

/**
 * Detect videos from Open Graph and meta tags
 */
function detectMetaVideos(): DetectedVideo[] {
  const videos: DetectedVideo[] = [];
  const pageTitle = extractPageTitle();
  const thumbnail = extractThumbnail();

  const ogVideo = document.querySelector('meta[property="og:video"]');
  const ogVideoSecure = document.querySelector('meta[property="og:video:secure_url"]');
  const ogVideoType = document.querySelector('meta[property="og:video:type"]');

  const videoUrl = ogVideoSecure?.getAttribute('content') || ogVideo?.getAttribute('content');

  if (videoUrl && isValidVideoUrl(videoUrl) && isFullVideo(videoUrl)) {
    videos.push({
      id: generateVideoId(videoUrl),
      url: videoUrl,
      type: ogVideoType?.getAttribute('content') || getMimeType(videoUrl),
      title: pageTitle,
      thumbnail,
      source: 'og-meta',
    });
  }

  return videos;
}

/**
 * Detect videos from JSON-LD structured data
 */
function detectJsonLdVideos(): DetectedVideo[] {
  const videos: DetectedVideo[] = [];
  const scripts = document.querySelectorAll('script[type="application/ld+json"]');
  const pageTitle = extractPageTitle();

  scripts.forEach((script) => {
    try {
      const data = JSON.parse(script.textContent || '');
      const items = Array.isArray(data) ? data : [data];

      const processItem = (item: Record<string, unknown>) => {
        if (item['@type'] === 'VideoObject') {
          const contentUrl = item.contentUrl as string;
          const embedUrl = item.embedUrl as string;
          const url = contentUrl || embedUrl;

          if (url && isValidVideoUrl(url) && isFullVideo(url)) {
            videos.push({
              id: generateVideoId(url),
              url,
              type: getMimeType(url),
              title: (item.name as string) || pageTitle,
              duration: item.duration ? parseDuration(item.duration as string) : undefined,
              thumbnail: (item.thumbnailUrl as string) || undefined,
              source: 'json-ld',
            });
          }
        }

        if (item['@graph'] && Array.isArray(item['@graph'])) {
          (item['@graph'] as Record<string, unknown>[]).forEach(processItem);
        }
      };

      items.forEach(processItem);
    } catch {
      // Invalid JSON
    }
  });

  return videos;
}

/**
 * Parse ISO 8601 duration to seconds
 */
function parseDuration(duration: string): number | undefined {
  const match = duration.match(/PT(?:(\d+)H)?(?:(\d+)M)?(?:(\d+)S)?/);
  if (!match) return undefined;

  const hours = parseInt(match[1] || '0', 10);
  const minutes = parseInt(match[2] || '0', 10);
  const seconds = parseInt(match[3] || '0', 10);

  return hours * 3600 + minutes * 60 + seconds;
}

/**
 * Site-specific: Detect Instagram videos
 */
function detectInstagramVideos(): DetectedVideo[] {
  const videos: DetectedVideo[] = [];
  const hostname = window.location.hostname;

  if (!hostname.includes('instagram.com')) return videos;

  const pageTitle = extractPageTitle();
  const thumbnail = extractThumbnail();

  const scripts = document.querySelectorAll('script');
  scripts.forEach((script) => {
    const content = script.textContent || '';

    // Look for video_url patterns - but filter out init segments
    const patterns = [
      /"video_url"\s*:\s*"([^"]+)"/g,
      /"playback_url"\s*:\s*"([^"]+)"/g,
    ];

    patterns.forEach((pattern) => {
      let match;
      while ((match = pattern.exec(content)) !== null) {
        try {
          const url = match[1]
            .replace(/\\u0026/g, '&')
            .replace(/\\u002F/g, '/')
            .replace(/\\/g, '');

          // Filter: Must be a valid video and not an init segment
          if (url && isValidVideoUrl(url) && isFullVideo(url)) {
            videos.push({
              id: generateVideoId(url),
              url,
              type: 'video/mp4',
              title: pageTitle,
              quality: extractQualityFromUrl(url) || '720p',
              thumbnail,
              source: 'instagram',
            });
          }
        } catch {
          // Invalid URL
        }
      }
    });
  });

  return videos;
}

/**
 * Site-specific: Detect Twitter/X videos
 */
function detectTwitterVideos(): DetectedVideo[] {
  const videos: DetectedVideo[] = [];
  const hostname = window.location.hostname;

  if (!hostname.includes('twitter.com') && !hostname.includes('x.com')) return videos;

  const pageTitle = extractPageTitle();
  const thumbnail = extractThumbnail();

  const scripts = document.querySelectorAll('script');
  scripts.forEach((script) => {
    const content = script.textContent || '';

    const pattern = /"url"\s*:\s*"(https:[^"]*video[^"]*\.mp4[^"]*)"/g;
    let match;
    while ((match = pattern.exec(content)) !== null) {
      try {
        const url = match[1].replace(/\\/g, '');
        if (isValidVideoUrl(url)) {
          videos.push({
            id: generateVideoId(url),
            url,
            type: 'video/mp4',
            title: pageTitle,
            quality: extractQualityFromUrl(url),
            thumbnail,
            source: 'twitter',
          });
        }
      } catch {
        // Invalid URL
      }
    }
  });

  return videos;
}

/**
 * Site-specific: Detect TikTok videos
 */
function detectTikTokVideos(): DetectedVideo[] {
  const videos: DetectedVideo[] = [];
  const hostname = window.location.hostname;

  if (!hostname.includes('tiktok.com')) return videos;

  const pageTitle = extractPageTitle();
  const thumbnail = extractThumbnail();

  const scripts = document.querySelectorAll('script');
  scripts.forEach((script) => {
    const content = script.textContent || '';

    const patterns = [
      /"playAddr"\s*:\s*"([^"]+)"/g,
      /"downloadAddr"\s*:\s*"([^"]+)"/g,
    ];

    patterns.forEach((pattern) => {
      let match;
      while ((match = pattern.exec(content)) !== null) {
        try {
          const url = decodeURIComponent(match[1].replace(/\\u002F/g, '/').replace(/\\/g, ''));
          if (url && (url.includes('.mp4') || url.includes('tiktokcdn'))) {
            videos.push({
              id: generateVideoId(url),
              url,
              type: 'video/mp4',
              title: pageTitle,
              thumbnail,
              source: 'tiktok',
            });
          }
        } catch {
          // Invalid URL
        }
      }
    });
  });

  return videos;
}

/**
 * Add intercepted video
 */
export function addInterceptedVideo(video: DetectedVideo): void {
  interceptedVideos.set(video.id, video);
}

/**
 * Get all intercepted videos
 */
export function getInterceptedVideos(): DetectedVideo[] {
  return Array.from(interceptedVideos.values());
}

/**
 * Clear intercepted videos
 */
export function clearInterceptedVideos(): void {
  interceptedVideos.clear();
}

/**
 * Remove duplicate videos by URL
 */
function deduplicateVideos(videos: DetectedVideo[]): DetectedVideo[] {
  const seen = new Map<string, DetectedVideo>();

  videos.forEach((video) => {
    // Normalize URL for comparison (remove query params for dedup)
    const normalizedUrl = video.url.split('?')[0];

    if (!seen.has(normalizedUrl)) {
      seen.set(normalizedUrl, video);
    } else {
      const existing = seen.get(normalizedUrl)!;
      // Prefer videos with better metadata
      if ((video.quality && !existing.quality) ||
          (video.duration && !existing.duration) ||
          (video.thumbnail && !existing.thumbnail) ||
          (video.title !== 'Instagram' && existing.title === 'Instagram')) {
        seen.set(normalizedUrl, { ...existing, ...video });
      }
    }
  });

  return Array.from(seen.values());
}

/**
 * Main function to detect all videos on the page
 */
export function detectVideos(): DetectedVideo[] {
  const allVideos = [
    ...detectVideoElements(),
    ...detectMetaVideos(),
    ...detectJsonLdVideos(),
    ...detectInstagramVideos(),
    ...detectTwitterVideos(),
    ...detectTikTokVideos(),
    ...getInterceptedVideos(),
  ];

  // Filter and validate
  const validVideos = allVideos.filter((video) => {
    try {
      new URL(video.url);
      return isFullVideo(video.url);
    } catch {
      return false;
    }
  });

  return deduplicateVideos(validVideos);
}

/**
 * Format duration in seconds to human readable string
 */
export function formatDuration(seconds?: number): string {
  if (!seconds || isNaN(seconds)) return '';

  const hours = Math.floor(seconds / 3600);
  const minutes = Math.floor((seconds % 3600) / 60);
  const secs = Math.floor(seconds % 60);

  if (hours > 0) {
    return `${hours}:${minutes.toString().padStart(2, '0')}:${secs.toString().padStart(2, '0')}`;
  }
  return `${minutes}:${secs.toString().padStart(2, '0')}`;
}

/**
 * Format file size to human readable string
 */
export function formatFileSize(bytes: number): string {
  if (bytes === 0) return '0 Bytes';

  const k = 1024;
  const sizes = ['Bytes', 'KB', 'MB', 'GB'];
  const i = Math.floor(Math.log(bytes) / Math.log(k));

  return parseFloat((bytes / Math.pow(k, i)).toFixed(2)) + ' ' + sizes[i];
}

/**
 * Convert string to URL-friendly slug
 */
export function slugify(text: string): string {
  return text
    .toString()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '') // Remove accents
    .toLowerCase()
    .trim()
    .replace(/[^a-z0-9\s-]/g, '') // Remove non-alphanumeric
    .replace(/\s+/g, '-') // Replace spaces with -
    .replace(/-+/g, '-') // Replace multiple - with single -
    .replace(/^-+|-+$/g, '') // Remove leading/trailing -
    .slice(0, 80); // Limit length
}

