        if (url.includes('.mp4') && url.includes('cdninstagram') && !url.includes('dashinit')) {
          console.log(`[VIDEO] ${url.substring(0, 80)}...`);
        }
      });

      await page.goto(reelUrl, { waitUntil: 'domcontentloaded' });

      console.log('\n' + '='.repeat(60));
      console.log('MODO INTERATIVO');
      console.log('='.repeat(60));
      console.log(`\nExtension ID: ${extensionId}`);
      console.log(`\nInstruções:`);
      console.log('1. Clique no ícone da extensão (quebra-cabeça) no Chrome');
      console.log('2. Clique em "Video Downloader"');
