/**
 * Video detection utilities for finding video elements and sources on web pages
 * Supports detection via DOM, meta tags, network interception, and site-specific extractors
 */

export interface DetectedVideo {
  id: string;
  url: string;
  type: string;
  title: string;
  duration?: number;
  width?: number;
  height?: number;
  quality?: string;
  thumbnail?: string;
  source?: string;
}

// Store intercepted video URLs from network requests
const interceptedVideos: Map<string, DetectedVideo> = new Map();

/**
 * Generate a unique ID for a video
 */
function generateVideoId(url: string): string {
  let hash = 0;
  for (let i = 0; i < url.length; i++) {
    const char = url.charCodeAt(i);
    hash = ((hash << 5) - hash) + char;
    hash = hash & hash;
  }
  return Math.abs(hash).toString(36);
}

/**
 * Extract title from the page based on site
 */
function extractPageTitle(): string {
  const hostname = window.location.hostname;

  // YouTube-specific title extraction
  if (hostname.includes('youtube.com') || hostname.includes('youtu.be')) {
    // For shorts, get the title from the page
    const ytTitle = document.querySelector('yt-formatted-string.ytd-watch-metadata, h1.ytd-watch-metadata yt-formatted-string, #title h1 yt-formatted-string');
    if (ytTitle?.textContent?.trim()) {
      return ytTitle.textContent.trim().slice(0, 80);
    }

    // Try shorts-specific selectors
    const shortsTitle = document.querySelector('[class*="shorts"] h2, ytd-reel-video-renderer h2');
    if (shortsTitle?.textContent?.trim()) {
      return shortsTitle.textContent.trim().slice(0, 80);
    }

    // Fallback to meta description
    const metaDesc = document.querySelector('meta[name="description"]');
    if (metaDesc?.getAttribute('content')) {
      const desc = metaDesc.getAttribute('content')!;
      // Take first sentence or 80 chars
      const firstSentence = desc.split('.')[0].trim();
      if (firstSentence.length > 5) {
        return firstSentence.slice(0, 80);
      }
    }
  }

  // Instagram-specific title extraction
  if (hostname.includes('instagram.com')) {
    // Try to get username and caption
    const usernameEl = document.querySelector('header a[role="link"] span, a[href*="/"] > div > span');
    const captionEl = document.querySelector('h1, span[dir="auto"]');

    let title = '';

    // Get username
    const userLink = document.querySelector('header a[href*="/"]');
    if (userLink) {
      const href = userLink.getAttribute('href');
      if (href) {
        const username = href.replace(/\//g, '');
        if (username && username.length > 0 && username.length < 50) {
          title = `@${username}`;
        }
      }
    }

    // Try to get caption/description
    const metaDesc = document.querySelector('meta[property="og:description"]');
    if (metaDesc) {
      const desc = metaDesc.getAttribute('content');
      if (desc) {
        // Extract first part of caption (before hashtags usually)
        const caption = desc.split(/[#@]/)[0].trim().slice(0, 60);
        if (caption) {
          title = title ? `${title} - ${caption}` : caption;
        }
      }
    }

    if (title) return title;
  }

  // Twitter/X specific
  if (hostname.includes('twitter.com') || hostname.includes('x.com')) {
    const tweetText = document.querySelector('[data-testid="tweetText"]');
    if (tweetText?.textContent) {
      return tweetText.textContent.slice(0, 60).trim();
    }
  }

  // TikTok specific
  if (hostname.includes('tiktok.com')) {
    const descEl = document.querySelector('[data-e2e="browse-video-desc"], [data-e2e="video-desc"]');
    if (descEl?.textContent) {
      return descEl.textContent.slice(0, 60).trim();
    }
  }

  // Generic: Use page title, cleaned up
  const pageTitle = document.title || 'Untitled Video';
  return pageTitle
    .replace(/\s*[-|•·]\s*(YouTube|Instagram|Twitter|Facebook|TikTok|X).*$/i, '')
    .replace(/\s*on\s*(YouTube|Instagram|Twitter|Facebook|TikTok|X)$/i, '')
    .trim()
    .slice(0, 80) || 'Untitled Video';
}

/**
 * Determine video quality from dimensions
 */
function getQualityLabel(width?: number, height?: number): string {
  if (!width || !height) return 'Unknown';

  const maxDim = Math.max(width, height);
  if (maxDim >= 2160) return '4K';
  if (maxDim >= 1440) return '1440p';
  if (maxDim >= 1080) return '1080p';
  if (maxDim >= 720) return '720p';
  if (maxDim >= 480) return '480p';
  if (maxDim >= 360) return '360p';
  return '240p';
}

