  const videoPatterns = [
    /\.(mp4|webm|ogg|ogv|mov|avi|mkv|m4v)(\?|$)/i,
    /video/i,
    /googlevideo\.com/i,
    /fbcdn.*video/i,
    /cdninstagram.*video/i,
