/**
 * Analisa URLs do Instagram para encontrar padrões de vídeos válidos
 */

import { test, chromium } from '@playwright/test';
import path from 'path';
import { fileURLToPath } from 'url';
import fs from 'fs';

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const extensionPath = path.join(__dirname, '../.output/chrome-mv3');

test('analyze Instagram video URLs', async () => {
  test.setTimeout(120000);

  const context = await chromium.launchPersistentContext('', {
    headless: false,
    args: [
      `--disable-extensions-except=${extensionPath}`,
      `--load-extension=${extensionPath}`,
      '--no-sandbox',
    ],
  });

  try {
    const page = await context.newPage();
    const reelUrl = process.env.INSTAGRAM_REEL_URL || 'https://www.instagram.com/reels/DIQ7_K6RHcW/';

    // Captura TODAS as URLs do cdninstagram
    const allUrls: { url: string; contentType: string; size: number }[] = [];

    page.on('response', async (response) => {
      const url = response.url();
      if (url.includes('cdninstagram.com') || url.includes('instagram')) {
        const contentType = response.headers()['content-type'] || '';
        const contentLength = parseInt(response.headers()['content-length'] || '0', 10);

        // Só captura se parecer ser mídia
        if (contentType.includes('video') ||
            contentType.includes('octet-stream') ||
            url.includes('/v/') ||
            contentLength > 100000) {
          allUrls.push({
            url,
            contentType,
            size: contentLength,
          });
        }
      }
    });

    console.log(`\nNavigating to: ${reelUrl}`);
    await page.goto(reelUrl, { waitUntil: 'networkidle' });
    await page.waitForTimeout(8000);

    console.log(`\n${'='.repeat(80)}`);
    console.log('ANÁLISE DE URLs DO INSTAGRAM');
    console.log(`${'='.repeat(80)}\n`);

    // Agrupa por padrão de URL
    const patterns: Record<string, typeof allUrls> = {};

    allUrls.forEach(item => {
      // Extrai o padrão da URL (ex: /v/t16/f2/m69/)
      const pathMatch = item.url.match(/\/v\/([^/]+)\/([^/]+)\/([^/]+)\//);
      const pattern = pathMatch ? `${pathMatch[1]}/${pathMatch[2]}/${pathMatch[3]}` : 'other';

      if (!patterns[pattern]) {
        patterns[pattern] = [];
      }
      patterns[pattern].push(item);
    });

    console.log('Padrões encontrados:\n');

    Object.entries(patterns).forEach(([pattern, items]) => {
      const totalSize = items.reduce((sum, i) => sum + i.size, 0);
      const avgSize = Math.round(totalSize / items.length / 1024);
      const uniqueUrls = [...new Set(items.map(i => i.url))];

      console.log(`📁 Padrão: ${pattern}`);
      console.log(`   Quantidade: ${uniqueUrls.length} URLs únicas`);
      console.log(`   Tamanho médio: ${avgSize} KB`);
      console.log(`   Content-Type: ${items[0]?.contentType || 'N/A'}`);

      // Mostra uma URL de exemplo
      if (uniqueUrls.length > 0) {
        const exampleUrl = uniqueUrls[0];
        console.log(`   Exemplo: ${exampleUrl.substring(0, 100)}...`);

        // Analisa características da URL
        const hasVideo = exampleUrl.includes('video');
        const hasMp4 = exampleUrl.includes('.mp4');
        const hasProgressive = exampleUrl.includes('progressive');
        const hasDuration = exampleUrl.includes('duration');
        const hasEfg = exampleUrl.includes('efg=');
        const hasOh = exampleUrl.includes('oh=');

        console.log(`   Características: video=${hasVideo}, mp4=${hasMp4}, progressive=${hasProgressive}, duration=${hasDuration}, efg=${hasEfg}, oh=${hasOh}`);
      }
      console.log('');
    });

    // Encontra URLs maiores (provavelmente vídeos completos)
    const largeUrls = allUrls.filter(u => u.size > 500000); // > 500KB
    console.log(`\n${'='.repeat(80)}`);
    console.log(`URLs GRANDES (>500KB) - Provavelmente vídeos completos: ${largeUrls.length}`);
    console.log(`${'='.repeat(80)}\n`);

    const uniqueLargeUrls = [...new Set(largeUrls.map(u => u.url))];
    uniqueLargeUrls.slice(0, 5).forEach((url, i) => {
      const item = largeUrls.find(u => u.url === url)!;
      console.log(`${i + 1}. [${Math.round(item.size / 1024)} KB] ${item.contentType}`);
      console.log(`   ${url.substring(0, 150)}`);
      console.log('');
    });

    // Salva todas as URLs para análise offline
    const outputPath = path.join(__dirname, '../test-results/instagram-urls.json');
    fs.mkdirSync(path.dirname(outputPath), { recursive: true });
    fs.writeFileSync(outputPath, JSON.stringify(allUrls, null, 2));
    console.log(`\nURLs salvas em: ${outputPath}`);

    console.log('\nBrowser fechando em 3 segundos...');
    await page.waitForTimeout(3000);

  } finally {
    await context.close();
  }
});

